# ---- Events ----
AcademicEvent.objects.filter(settings=config).delete()
events = [{'id': '1775777704517', 'date': '2 Septembre 2026', 'title': 'Rentrée Académique 2026 / 2027', 'type': 'Événement', 'lieu': 'Campus Douala', 'description': 'La Rentre Scolaire', 'image': None}, {'id': '1775781752962', 'date': '16 OCT 2026', 'title': 'TEST EVENT', 'type': 'Événement', 'lieu': 'CAMPUS FRANCE', 'description': '', 'image': None}]
for i, e in enumerate(events):
    fid = e.get('id', '')
    if fid:
        AcademicEvent.objects.create(
            settings=config,
            order=i,
            frontend_id=fid,
            title=e.get('title',''),
            date=e.get('date',''),
            event_type=e.get('type',''),
            location=e.get('lieu',''),
            description=e.get('description','')
        )
print(f"✅ {len(events)} Événements créés")

# ---- Testimonials ----
Testimonial.objects.filter(settings=config).delete()
testimonials = [{'id': '1775782016151', 'name': 'KAMGA', 'role': 'Diplome de BTS 2024', 'content': 'tres belle experience', 'rating': 4, 'avatar': None}]
for i, t in enumerate(testimonials):
    fid = t.get('id', '')
    if fid:
        Testimonial.objects.create(
            settings=config,
            order=i,
            frontend_id=fid,
            name=t.get('name',''),
            role=t.get('role',''),
            content=t.get('content',''),
            rating=t.get('rating',5)
        )
print(f"✅ {len(testimonials)} Témoignages créés")

# ---- Exam Results ----
from core.models import ExamResult
ExamResult.objects.filter(settings=config).delete()
exam_results = [{'id': '1775776347496', 'year': '2025', 'program': 'DQP', 'result_text': '26 Admis'}, {'id': '1775776495796', 'year': '2025', 'program': 'CQP', 'result_text': '20 Admis'}, {'id': '1783083133796', 'year': '2025', 'program': 'BTS', 'result_text': '40 Admis'}]
for i, er in enumerate(exam_results):
    fid = er.get('id', '')
    if fid:
        ExamResult.objects.create(
            settings=config,
            order=i,
            frontend_id=fid,
            year=er.get('year',''),
            program=er.get('program',''),
            result_text=er.get('result_text','')
        )

